29: /**
30:  * A container that holds the list {@link ConsumerRecord} per partition for a
31:  * particular topic. There is one {@link ConsumerRecord} list for every topic
32:  * partition returned by a {@link Consumer#poll(java.time.Duration)} operation.
33:  */
34: public class ConsumerRecords<K, V> implements Iterable<ConsumerRecord<K, V>> {
35:     public static final ConsumerRecords<Object, Object> EMPTY = new ConsumerRecords<>(Collections.emptyMap());
36: 
37:     private final Map<TopicPartition, List<ConsumerRecord<K, V>>> records;
38: 
39:     public ConsumerRecords(Map<TopicPartition, List<ConsumerRecord<K, V>>> records) {
40:         this.records = records;
41:     }
42: 
43:     /**
44:      * Get just the records for the given partition
45:      * 
46:      * @param partition The partition to get records for
47:      */
48:     public List<ConsumerRecord<K, V>> records(TopicPartition partition) {
49:         List<ConsumerRecord<K, V>> recs = this.records.get(partition);
50:         if (recs == null)
51:             return Collections.emptyList();
52:         else
53:             return Collections.unmodifiableList(recs);
54:     }
55: 
56:     /**
57:      * Get just the records for the given topic
58:      */
59:     public Iterable<ConsumerRecord<K, V>> records(String topic) {
60:         if (topic == null)
61:             throw new IllegalArgumentException("Topic must be non-null.");
62:         List<List<ConsumerRecord<K, V>>> recs = new ArrayList<>();
63:         for (Map.Entry<TopicPartition, List<ConsumerRecord<K, V>>> entry : records.entrySet()) {
64:             if (entry.getKey().topic().equals(topic))
65:                 recs.add(entry.getValue());
66:         }
67:         return new ConcatenatedIterable<>(recs);
68:     }
69: 
70:     /**
71:      * Get the partitions which have records contained in this record set.
72:      * @return the set of partitions with data in this record set (may be empty if no data was returned)
73:      */
74:     public Set<TopicPartition> partitions() {
75:         return Collections.unmodifiableSet(records.keySet());
76:     }
77: 
78:     @Override
79:     public Iterator<ConsumerRecord<K, V>> iterator() {
80:         return new ConcatenatedIterable<>(records.values()).iterator();
81:     }
82: 
83:     /**
84:      * The number of records for all topics
85:      */
86:     public int count() {
87:         int count = 0;
88:         for (List<ConsumerRecord<K, V>> recs: this.records.values())
89:             count += recs.size();
90:         return count;
91:     }
