93:     private static class ConcatenatedIterable<K, V> implements Iterable<ConsumerRecord<K, V>> {
94: 
95:         private final Iterable<? extends Iterable<ConsumerRecord<K, V>>> iterables;
96: 
97:         public ConcatenatedIterable(Iterable<? extends Iterable<ConsumerRecord<K, V>>> iterables) {
98:             this.iterables = iterables;
99:         }
100: 
101:         @Override
102:         public Iterator<ConsumerRecord<K, V>> iterator() {
103:             return new AbstractIterator<ConsumerRecord<K, V>>() {
104:                 Iterator<? extends Iterable<ConsumerRecord<K, V>>> iters = iterables.iterator();
105:                 Iterator<ConsumerRecord<K, V>> current;
106: 
107:                 public ConsumerRecord<K, V> makeNext() {
108:                     while (current == null || !current.hasNext()) {
109:                         if (iters.hasNext())
110:                             current = iters.next().iterator();
111:                         else
112:                             return allDone();
113:                     }
114:                     return current.next();
115:                 }
116:             };
117:         }
118:     }
